phase1.code:
package main

import (
    "fmt"
    "time"
)

// ---- Functions as goroutines ----
func printNumbers(name string) {
    for i := 1; i <= 3; i++ {
        fmt.Printf("%s: %d\n", name, i)
        time.Sleep(50 * time.Millisecond)
    }
}

// ---- Anonymous functions as goroutines ----
func main() {
    fmt.Println("=== Launching Goroutines ===")

    // ---- Named function ----
    go printNumbers("A")
    go printNumbers("B")

    // ---- Anonymous function ----
    go func() {
        for i := 1; i <= 3; i++ {
            fmt.Printf("C: %d\n", i)
            time.Sleep(50 * time.Millisecond)
        }
    }()

    // ---- Function with parameters ----
    go func(msg string, count int) {
        for i := 0; i < count; i++ {
            fmt.Println(msg, i)
            time.Sleep(50 * time.Millisecond)
        }
    }("D:", 3)

    // ---- Goroutines with closures ----
    for i := 0; i < 3; i++ {
        // Capturing i by value
        go func(n int) {
            fmt.Printf("Closure: %d\n", n)
        }(i)
    }

    // ---- Wait for all to finish ----
    time.Sleep(500 * time.Millisecond)
    fmt.Println("Done")
}

phase2.brokenCode:
package main

import (
    "fmt"
    "time"
)

func main() {
    // Closure captures the loop variable incorrectly
    for i := 0; i < 3; i++ {
        go func() {
            fmt.Println(i)  // i is captured by reference
        }()
    }
    time.Sleep(100 * time.Millisecond)
}

phase2.explanation:
Closures capture variables by reference, so all goroutines see the final value of `i`.

**The fix:**
```go
for i := 0; i < 3; i++ {
    go func(n int) {
        fmt.Println(n)  // n is captured by value
    }(i)
}
```

**Go-chan says:**
"Capture values, not variables, in closures."

phase3.solution:
package main

import (
    "fmt"
    "time"
)

func printHello(id int) {
    fmt.Printf("Hello from %d\n", id)
}

func main() {
    for i := 1; i <= 4; i++ {
        go printHello(i)
    }

    for i := 1; i <= 2; i++ {
        go func(n int) {
            fmt.Printf("Anonymous from %d\n", n)
        }(i)
    }

    time.Sleep(100 * time.Millisecond)
    fmt.Println("Done")
}
